Resource: aws_s3_bucket.logs
File: /s3.tf: 113-141
Guideline: https://docs.prismacloud.io/en/enterprise-edition/policy-reference/aws-policies/aws-general-policies/ensure-that-s3-bucket-has-cross-region-replication-enabled

		113 | resource "aws_s3_bucket" "logs" {
		114 |   bucket = "${local.resource_prefix.value}-logs"
		115 |   acl    = "log-delivery-write"
		116 |   versioning {
		117 |     enabled = true
		118 |   }
		119 |   server_side_encryption_configuration {
		120 |     rule {
		121 |       apply_server_side_encryption_by_default {
		122 |         sse_algorithm     = "aws:kms"
		123 |         kms_master_key_id = "${aws_kms_key.logs_key.arn}"
